import React, { useContext, useEffect, useState } from 'react'
import { useParams ,Navigate } from 'react-router-dom'
import { UserContext } from '../context/UserContext'
import axios from 'axios'

const OneItemList = () => {
    let {id }=  useParams()
    const {user ,ready} = useContext(UserContext)
    const [itemData ,setItemData] = useState({}) 
    const [bookingData ,setBookingData] = useState({})   
    useEffect(()=>{
        if(user)
        {
            axios.defaults.headers.common.Authorization = `Bearer ${user?.token}`
            const fetchData =async()=>{
                try {
                    const response = await axios.get(`/items/getbyid/${id}`)
                    setItemData(...response.data)
                } catch (error) {
                    console.log(error)
                }
            }
            fetchData()
        }
    },[user])
    
    if (ready && !user) {
        return <Navigate to={"/register"} />;
      }

      const bookItem = async()=>{
        
        // const response = await axios.post('')  
      }

  return (
    <div>
        <div className='flex justify-center mt-10' >

        <div className=''>
            <h1>Single Item</h1>
            <h2>{itemData.iname}</h2>
            <div>
            {
                itemData.photos?.map((pic,index)=>(
                    <div className="h-32 flex max-w-96 p-2 justify-center"  key={index}>
                          <img
                            className="rounded-2xl w-full object-cover"
                            alt="img not found"
                            src={"http://localhost:5000/" +pic}
                            />
                        </div>
                ))

            }
            </div>
            <h2>{itemData.imrp}</h2>
            <button className='cursor-pointer px-6 py-3 bg-green-500' onClick={bookItem}>Buy Now</button>
        </div>
        </div>
    </div>
  )
}


export default OneItemList
